#!/bin/bash\n\n# ============================================\n# AWS DEPLOYMENT SCRIPT FOR N8N REVENUE SYSTEM\n# ============================================\n# Deploys N8N to AWS ECS with RDS PostgreSQL\n\necho \"🚀 N8N Revenue System - AWS Deployment\"\necho \"========================================\"\necho \"\"\n\n# Check if AWS CLI is installed\nif ! command -v aws &> /dev/null; then\n    echo \"❌ AWS CLI not found. Install it from: https://aws.amazon.com/cli/\"\n    exit 1\nfi\n\necho \"✅ AWS CLI found\"\necho \"\"\n\n# Get configuration from user\nread -p \"Enter AWS Region (default: us-east-1): \" AWS_REGION\nAWS_REGION=${AWS_REGION:-us-east-1}\n\nread -p \"Enter ECR Repository Name (default: n8n-revenue): \" ECR_REPO\nECR_REPO=${ECR_REPO:-n8n-revenue}\n\nread -p \"Enter ECS Cluster Name (default: n8n-cluster): \" ECS_CLUSTER\nECS_CLUSTER=${ECS_CLUSTER:-n8n-cluster}\n\necho \"\"\necho \"📋 Deployment Configuration:\"\necho \"   Region: $AWS_REGION\"\necho \"   ECR Repo: $ECR_REPO\"\necho \"   ECS Cluster: $ECS_CLUSTER\"\necho \"\"\n\necho \"1️⃣  Getting AWS Account ID...\"\nAWS_ACCOUNT_ID=$(aws sts get-caller-identity --query Account --output text)\necho \"✅ Account ID: $AWS_ACCOUNT_ID\"\n\necho \"\"\necho \"2️⃣  Creating ECR Repository...\"\naws ecr create-repository \\\n    --repository-name $ECR_REPO \\\n    --region $AWS_REGION \\\n    2>/dev/null\n\necho \"✅ ECR Repository created (or already exists)\"\n\necho \"\"\necho \"3️⃣  Building Docker image...\"\necho \"Building from Dockerfile...\"\ndocker build -t $ECR_REPO:latest .\n\necho \"\"\necho \"4️⃣  Logging into ECR...\"\naws ecr get-login-password --region $AWS_REGION | docker login --username AWS --password-stdin $AWS_ACCOUNT_ID.dkr.ecr.$AWS_REGION.amazonaws.com\n\necho \"\"\necho \"5️⃣  Tagging and pushing image to ECR...\"\nIMAGE_URI=\"$AWS_ACCOUNT_ID.dkr.ecr.$AWS_REGION.amazonaws.com/$ECR_REPO:latest\"\n\ndocker tag $ECR_REPO:latest $IMAGE_URI\ndocker push $IMAGE_URI\n\necho \"✅ Image pushed to ECR\"\n\necho \"\"\necho \"6️⃣  Creating RDS PostgreSQL Database...\"\necho \"Note: This may take 5-10 minutes...\"\n\naws rds create-db-instance \\\n    --db-instance-identifier n8n-revenue-db \\\n    --db-instance-class db.t3.micro \\\n    --engine postgres \\\n    --master-username revenue_admin \\\n    --master-user-password $(openssl rand -base64 12) \\\n    --allocated-storage 20 \\\n    --publicly-accessible false \\\n    --region $AWS_REGION \\\n    2>/dev/null\n\necho \"✅ RDS instance created (or already exists)\"\n\necho \"\"\necho \"7️⃣  Creating ECS Cluster...\"\naws ecs create-cluster \\\n    --cluster-name $ECS_CLUSTER \\\n    --region $AWS_REGION \\\n    2>/dev/null\n\necho \"✅ ECS Cluster created (or already exists)\"\n\necho \"\"\necho \"===========================================\"\necho \"✅ AWS DEPLOYMENT CONFIGURED!\"\necho \"===========================================\"\necho \"\"\necho \"Manual Next Steps:\"\necho \"\"\necho \"1. Go to AWS Console → ECS\"\necho \"2. Create Task Definition:\"\necho \"   - Name: n8n-revenue\"\necho \"   - Container image: $IMAGE_URI\"\necho \"   - Port mapping: 5678:5678\"\necho \"   - Environment variables:\"\necho \"     * DB_HOST: (RDS endpoint)\"\necho \"     * DB_USER: revenue_admin\"\necho \"     * DB_PASSWORD: (your password)\"\necho \"     * N8N_PROTOCOL: https\"\necho \"\"\necho \"3. Create Service:\"\necho \"   - Cluster: $ECS_CLUSTER\"\necho \"   - Task definition: n8n-revenue\"\necho \"   - Desired count: 1\"\necho \"   - Load balancer: Application Load Balancer\"\necho \"\"\necho \"4. Configure Route 53 DNS\"\necho \"\"\necho \"5. Set up CloudFront CDN (optional)\"\necho \"\"\necho \"📚 AWS Documentation: https://docs.aws.amazon.com/ecs/\"\necho \"\"\n"
